/**
 * Available search algorithms.
 */
export type SearchAlgorithm = 'basic' | 'ranked' | 'boolean' | 'fuzzy' | 'semantic';

/**
 * Cost estimate for a search operation.
 */
export interface CostEstimate {
  /** Estimated number of entity iterations required */
  entityIterations: number;

  /** Estimated number of index lookups */
  indexLookups: number;

  /** Estimated execution time in milliseconds */
  estimatedMs: number;

  /** Complexity class: 'low', 'medium', 'high', 'very_high' */
  complexity: 'low' | 'medium' | 'high' | 'very_high';

  /** Confidence level of the estimate (0.0 to 1.0) */
  confidence: number;

  /** Whether the query can use indexes effectively */
  canUseIndex: boolean;

  /** Recommended algorithm for this query */
  recommendedAlgorithm: SearchAlgorithm;

  /** Human-readable explanation of the estimate */
  explanation: string;
}

/**
 * Analysis of query characteristics.
 */
export interface QueryAnalysis {
  /** Number of terms in the query */
  termCount: number;

  /** Whether query uses field specifiers (name:, type:, etc.) */
  hasFieldSpecifiers: boolean;

  /** Whether query uses boolean operators */
  hasBooleanOperators: boolean;

  /** Whether query requires fuzzy matching */
  requiresFuzzy: boolean;

  /** Whether query benefits from ranking */
  benefitsFromRanking: boolean;

  /** Fields targeted by the query */
  targetFields: string[];
}

/**
 * Cost constants for estimation (calibrated through benchmarks).
 * @internal
 */
const COST_CONSTANTS = {
  /** Microseconds per entity for basic string matching */
  BASIC_MATCH_US_PER_ENTITY: 5,

  /** Microseconds per entity for TF-IDF scoring */
  TFIDF_SCORE_US_PER_ENTITY: 15,

  /** Microseconds per entity for fuzzy matching (Levenshtein) */
  FUZZY_MATCH_US_PER_ENTITY: 50,

  /** Microseconds per entity for semantic search (vector comparison) */
  SEMANTIC_COMPARE_US_PER_ENTITY: 2,

  /** Microseconds per index lookup (NameIndex, TypeIndex) */
  INDEX_LOOKUP_US: 1,

  /** Threshold for 'low' complexity (entities) */
  LOW_COMPLEXITY_THRESHOLD: 100,

  /** Threshold for 'medium' complexity (entities) */
  MEDIUM_COMPLEXITY_THRESHOLD: 1000,

  /** Threshold for 'high' complexity (entities) */
  HIGH_COMPLEXITY_THRESHOLD: 10000,
} as const;

/**
 * Estimates query execution cost based on query characteristics and graph state.
 *
 * @example
 * ```typescript
 * const estimator = new QueryCostEstimator();
 * const stats = await storage.getGraphStats();
 *
 * // Estimate cost for a search
 * const cost = estimator.estimateSearch('machine learning', 'ranked', stats);
 * console.log(`Estimated time: ${cost.estimatedMs}ms`);
 * console.log(`Complexity: ${cost.complexity}`);
 * console.log(`Recommended: ${cost.recommendedAlgorithm}`);
 *
 * // Analyze a query
 * const analysis = estimator.analyzeQuery('name:Alice AND type:person');
 * console.log(`Terms: ${analysis.termCount}`);
 * console.log(`Uses boolean: ${analysis.hasBooleanOperators}`);
 * ```
 */
export class QueryCostEstimator {
  /**
   * Estimate the cost of a search operation.
   *
   * @param query - The search query string
   * @param algorithm - The search algorithm to use
   * @param stats - Current graph statistics
   * @returns Cost estimate with metrics and recommendations
   */
  estimateSearch(
    query: string,
    algorithm: SearchAlgorithm,
    stats: GraphStats
  ): CostEstimate {
    const analysis = this.analyzeQuery(query);
    const entityCount = stats.totalEntities;

    let entityIterations = entityCount;
    let indexLookups = 0;
    let usPerEntity = COST_CONSTANTS.BASIC_MATCH_US_PER_ENTITY;
    let canUseIndex = false;

    // Adjust based on algorithm
    switch (algorithm) {
      case 'basic':
        usPerEntity = COST_CONSTANTS.BASIC_MATCH_US_PER_ENTITY;
        // Can use name/type index for field-specific queries
        if (analysis.hasFieldSpecifiers && analysis.targetFields.length === 1) {
          const field = analysis.targetFields[0];
          if (field === 'name' || field === 'type') {
            canUseIndex = true;
            indexLookups = 1;
            entityIterations = Math.ceil(entityCount * 0.1); // Estimate 10% match
          }
        }
        break;

      case 'ranked':
        usPerEntity = COST_CONSTANTS.TFIDF_SCORE_US_PER_ENTITY;
        // Always iterates all entities for scoring
        break;

      case 'boolean':
        usPerEntity = COST_CONSTANTS.BASIC_MATCH_US_PER_ENTITY * 1.5;
        // Uses observation index for term lookups
        if (!analysis.hasBooleanOperators) {
          canUseIndex = true;
          indexLookups = analysis.termCount;
          entityIterations = Math.ceil(entityCount * 0.2);
        }
        break;

      case 'fuzzy':
        usPerEntity = COST_CONSTANTS.FUZZY_MATCH_US_PER_ENTITY;
        // Always iterates all entities (no index)
        break;

      case 'semantic':
        usPerEntity = COST_CONSTANTS.SEMANTIC_COMPARE_US_PER_ENTITY;
        // Vector comparison is fast but requires embedding lookup
        indexLookups = 1; // Embedding generation
        break;
    }

    // Calculate estimated time
    const estimatedMs =
      (entityIterations * usPerEntity) / 1000 +
      (indexLookups * COST_CONSTANTS.INDEX_LOOKUP_US) / 1000;

    // Determine complexity
    let complexity: CostEstimate['complexity'];
    if (entityIterations < COST_CONSTANTS.LOW_COMPLEXITY_THRESHOLD) {
      complexity = 'low';
    } else if (entityIterations < COST_CONSTANTS.MEDIUM_COMPLEXITY_THRESHOLD) {
      complexity = 'medium';
    } else if (entityIterations < COST_CONSTANTS.HIGH_COMPLEXITY_THRESHOLD) {
      complexity = 'high';
    } else {
      complexity = 'very_high';
    }

    // Determine recommended algorithm
    const recommendedAlgorithm = this.recommendAlgorithm(analysis, stats);

    // Calculate confidence (lower for larger graphs, complex queries)
    let confidence = 0.8;
    if (entityCount > 10000) confidence -= 0.1;
    if (analysis.hasBooleanOperators) confidence -= 0.1;
    if (algorithm === 'fuzzy') confidence -= 0.1;
    confidence = Math.max(0.5, confidence);

    // Generate explanation
    const explanation = this.generateExplanation(
      algorithm,
      entityIterations,
      indexLookups,
      canUseIndex,
      estimatedMs
    );

    return {
      entityIterations,
      indexLookups,
      estimatedMs: Math.round(estimatedMs * 100) / 100,
      complexity,
      confidence,
      canUseIndex,
      recommendedAlgorithm,
      explanation,
    };
  }

/**
 * Analyze a query string to determine its characteristics.
 *
 * @param query - The search query string
 * @returns Analysis of query characteristics
 */
analyzeQuery(query: string): QueryAnalysis {
  const normalized = query.toLowerCase().trim();

  // Check for field specifiers (name:, type:, observation:)
  const fieldPattern = /\b(name|type|observation|entitytype|obs):/gi;
  const fieldMatches = normalized.match(fieldPattern) || [];
  const hasFieldSpecifiers = fieldMatches.length > 0;

  // Extract target fields
  const targetFields = [...new Set(
    fieldMatches.map(m => m.replace(':', '').toLowerCase())
  )];

  // Check for boolean operators
  const hasBooleanOperators =
    /\b(AND|OR|NOT)\b/i.test(query) ||
    /[()]/g.test(query);

  // Count terms (excluding operators and field specifiers)
  const cleanQuery = normalized
    .replace(fieldPattern, '')
    .replace(/\b(and|or|not)\b/gi, '')
    .replace(/[()]/g, '')
    .trim();
  const terms = cleanQuery.split(/\s+/).filter(t => t.length > 0);
  const termCount = terms.length;

  // Determine if fuzzy matching might be needed
  const requiresFuzzy = /~\d*$/.test(query) || /\*|\?/.test(query);

  // Determine if ranking would benefit the query
  const benefitsFromRanking = termCount > 1 && !hasFieldSpecifiers;

  return {
    termCount,
    hasFieldSpecifiers,
    hasBooleanOperators,
    requiresFuzzy,
    benefitsFromRanking,
    targetFields,
  };
}

/**
 * Recommend the optimal search algorithm based on query and graph.
 *
 * @param analysis - Query analysis
 * @param stats - Graph statistics
 * @returns Recommended search algorithm
 */
recommendAlgorithm(analysis: QueryAnalysis, stats: GraphStats): SearchAlgorithm {
  // Fuzzy required for wildcard/similarity queries
  if (analysis.requiresFuzzy) {
    return 'fuzzy';
  }

  // Boolean for complex queries with operators
  if (analysis.hasBooleanOperators) {
    return 'boolean';
  }

  // For very large graphs, prefer index-based search
  if (stats.totalEntities > 10000) {
    if (analysis.hasFieldSpecifiers) {
      return 'boolean'; // Uses observation index
    }
    return 'basic'; // Simple but fast
  }

  // For multi-term queries, ranking is valuable
  if (analysis.benefitsFromRanking && stats.totalEntities > 100) {
    return 'ranked';
  }

  // Default to basic for simple queries
  return 'basic';
}

  /**
   * Generate human-readable explanation of the cost estimate.
   * @private
   */
  private generateExplanation(
    algorithm: SearchAlgorithm,
    entityIterations: number,
    indexLookups: number,
    canUseIndex: boolean,
    estimatedMs: number
  ): string {
    const parts: string[] = [];

    parts.push(`${algorithm} search`);

    if (canUseIndex) {
      parts.push(`uses index (${indexLookups} lookup${indexLookups > 1 ? 's' : ''})`);
      parts.push(`~${entityIterations} entities to scan`);
    } else {
      parts.push(`full scan of ${entityIterations} entities`);
    }

    parts.push(`~${estimatedMs.toFixed(1)}ms estimated`);

    return parts.join(', ');
  }
}

