  private costEstimator: QueryCostEstimator | null = null;
  private storage: GraphStorage;  // Add this if not already a private property

  /**
   * Get cost estimator instance (lazy init).
   * @private
   */
  private getCostEstimator(): QueryCostEstimator {
    if (!this.costEstimator) {
      this.costEstimator = new QueryCostEstimator();
    }
    return this.costEstimator;
  }

  /**
   * Get basic graph statistics for cost estimation.
   * Note: SearchManager needs a reference to storage. Either add 'private storage: GraphStorage' as a property and store from constructor, or inject these stats differently.
   * @private
   */
  private async getGraphStats(): Promise<GraphStats> {
    const graph = await this.storage.loadGraph();
    const entityTypesCounts: Record<string, number> = {};
    const relationTypesCounts: Record<string, number> = {};

    for (const entity of graph.entities) {
      entityTypesCounts[entity.entityType] = (entityTypesCounts[entity.entityType] || 0) + 1;
    }
    for (const relation of graph.relations) {
      relationTypesCounts[relation.relationType] = (relationTypesCounts[relation.relationType] || 0) + 1;
    }

    return {
      totalEntities: graph.entities.length,
      totalRelations: graph.relations.length,
      entityTypesCounts,
      relationTypesCounts,
    };
  }

