/**
 * Get cost estimate for a search operation.
 *
 * Analyzes the query and current graph state to estimate execution cost,
 * recommend optimal algorithm, and predict execution time.
 *
 * @param query - The search query string
 * @param algorithm - Algorithm to estimate (default: 'basic')
 * @returns Promise resolving to cost estimate
 *
 * @example
 * ```typescript
 * const cost = await searchManager.getCostEstimate('machine learning');
 * console.log(`Estimated time: ${cost.estimatedMs}ms`);
 * console.log(`Recommended: ${cost.recommendedAlgorithm}`);
 *
 * // Use recommendation
 * if (cost.recommendedAlgorithm === 'ranked') {
 *   const results = await searchManager.searchRanked('machine learning');
 * }
 * ```
 */
async getCostEstimate(
  query: string,
  algorithm: SearchAlgorithm = 'basic'
): Promise<CostEstimate> {
  const stats = await this.getGraphStats();
  return this.getCostEstimator().estimateSearch(query, algorithm, stats);
}

/**
 * Analyze a query to understand its characteristics.
 *
 * Useful for understanding what search features a query would use.
 *
 * @param query - The search query string
 * @returns Query analysis with term count, operators, etc.
 */
analyzeQuery(query: string): QueryAnalysis {
  return this.getCostEstimator().analyzeQuery(query);
}

/**
 * Search with automatic algorithm selection.
 *
 * Analyzes the query and graph state, then uses the optimal algorithm.
 * Returns results with the same format as search_nodes tool.
 *
 * @param query - The search query string
 * @param options - Optional search options (tags, importance, etc.)
 * @returns Promise resolving to search results with algorithm used
 *
 * @example
 * ```typescript
 * const result = await searchManager.searchAuto('machine learning');
 * console.log(`Used algorithm: ${result.algorithm}`);
 * console.log(`Found: ${result.entities.length} entities`);
 * ```
 */
async searchAuto(
  query: string,
  options: {
    tags?: string[];
    minImportance?: number;
    maxImportance?: number;
    entityType?: string;
    limit?: number;
  } = {}
): Promise<{
  entities: Entity[];
  algorithm: SearchAlgorithm;
  costEstimate: CostEstimate;
}> {
  const stats = await this.getGraphStats();
  const analysis = this.getCostEstimator().analyzeQuery(query);
  const recommended = this.getCostEstimator().recommendAlgorithm(analysis, stats);
  const costEstimate = this.getCostEstimator().estimateSearch(query, recommended, stats);

  let entities: Entity[];

  switch (recommended) {
    case 'ranked': {
      const results = await this.searchNodesRanked(
        query,
        options.tags,
        options.minImportance,
        options.maxImportance,
        options.entityType,
        options.limit
      );
      entities = results.map(r => r.entity);
      break;
    }

    case 'boolean': {
      entities = await this.booleanSearch(
        query,
        options.tags,
        options.minImportance,
        options.maxImportance,
        options.limit
      );
      break;
    }

    case 'fuzzy': {
      const results = await this.fuzzySearch(
        query,
        0.6, // Default threshold
        options.tags,
        options.minImportance,
        options.maxImportance,
        options.limit
      );
      entities = results.map(r => r.entity);
      break;
    }

    case 'basic':
    default: {
      entities = await this.searchNodes(
        query,
        options.tags,
        options.minImportance,
        options.maxImportance,
        options.entityType,
        options.limit
      );
      break;
    }
  }

  return {
    entities,
    algorithm: recommended,
    costEstimate,
  };
}

