import { describe, it, expect } from 'vitest';
import {
  QueryCostEstimator,
  type CostEstimate,
  type SearchAlgorithm,
} from '../../../src/search/QueryCostEstimator.js';
import type { GraphStats } from '../../../src/types/types.js';

const createMockStats = (entityCount: number): GraphStats => ({
  totalEntities: entityCount,
  totalRelations: Math.floor(entityCount * 0.5),
  entityTypesCounts: { test: entityCount },
  relationTypesCounts: { related: Math.floor(entityCount * 0.5) },
});

describe('QueryCostEstimator', () => {
  const estimator = new QueryCostEstimator();

  describe('analyzeQuery', () => {
    it('should detect simple queries', () => {
      const analysis = estimator.analyzeQuery('hello world');

      expect(analysis.termCount).toBe(2);
      expect(analysis.hasFieldSpecifiers).toBe(false);
      expect(analysis.hasBooleanOperators).toBe(false);
      expect(analysis.requiresFuzzy).toBe(false);
    });

    it('should detect field specifiers', () => {
      const analysis = estimator.analyzeQuery('name:Alice type:person');

      expect(analysis.hasFieldSpecifiers).toBe(true);
      expect(analysis.targetFields).toContain('name');
      expect(analysis.targetFields).toContain('type');
    });

    it('should detect boolean operators', () => {
      const analysis = estimator.analyzeQuery('foo AND bar OR baz');

      expect(analysis.hasBooleanOperators).toBe(true);
    });

    it('should detect parentheses as boolean', () => {
      const analysis = estimator.analyzeQuery('(foo OR bar)');

      expect(analysis.hasBooleanOperators).toBe(true);
    });

    it('should detect fuzzy queries', () => {
      const analysis = estimator.analyzeQuery('hello~2');

      expect(analysis.requiresFuzzy).toBe(true);
    });

    it('should identify ranking benefit for multi-term queries', () => {
      const simple = estimator.analyzeQuery('hello');
      const multi = estimator.analyzeQuery('machine learning models');

      expect(simple.benefitsFromRanking).toBe(false);
      expect(multi.benefitsFromRanking).toBe(true);
    });
  });

describe('estimateSearch', () => {
  it('should estimate basic search cost', () => {
    const stats = createMockStats(1000);
    const cost = estimator.estimateSearch('hello', 'basic', stats);

    expect(cost.entityIterations).toBe(1000);
    expect(cost.estimatedMs).toBeGreaterThan(0);
    expect(cost.complexity).toBe('medium');
    expect(cost.confidence).toBeGreaterThan(0);
    expect(cost.explanation).toContain('basic search');
  });

  it('should estimate higher cost for fuzzy search', () => {
    const stats = createMockStats(1000);
    const basic = estimator.estimateSearch('hello', 'basic', stats);
    const fuzzy = estimator.estimateSearch('hello', 'fuzzy', stats);

    expect(fuzzy.estimatedMs).toBeGreaterThan(basic.estimatedMs);
  });

  it('should use index for field-specific queries', () => {
    const stats = createMockStats(1000);
    const cost = estimator.estimateSearch('name:Alice', 'basic', stats);

    expect(cost.canUseIndex).toBe(true);
    expect(cost.indexLookups).toBeGreaterThan(0);
    expect(cost.entityIterations).toBeLessThan(1000);
  });

  it('should categorize complexity correctly', () => {
    const low = estimator.estimateSearch('x', 'basic', createMockStats(50));
    const medium = estimator.estimateSearch('x', 'basic', createMockStats(500));
    const high = estimator.estimateSearch('x', 'basic', createMockStats(5000));
    const veryHigh = estimator.estimateSearch('x', 'basic', createMockStats(50000));

    expect(low.complexity).toBe('low');
    expect(medium.complexity).toBe('medium');
    expect(high.complexity).toBe('high');
    expect(veryHigh.complexity).toBe('very_high');
  });
});

  describe('recommendAlgorithm', () => {
    it('should recommend fuzzy for wildcard queries', () => {
      const analysis = estimator.analyzeQuery('hello~2');
      const stats = createMockStats(1000);
      const recommended = estimator.recommendAlgorithm(analysis, stats);

      expect(recommended).toBe('fuzzy');
    });

    it('should recommend boolean for complex queries', () => {
      const analysis = estimator.analyzeQuery('foo AND bar');
      const stats = createMockStats(1000);
      const recommended = estimator.recommendAlgorithm(analysis, stats);

      expect(recommended).toBe('boolean');
    });

    it('should recommend ranked for multi-term queries', () => {
      const analysis = estimator.analyzeQuery('machine learning models');
      const stats = createMockStats(500);
      const recommended = estimator.recommendAlgorithm(analysis, stats);

      expect(recommended).toBe('ranked');
    });

    it('should recommend basic for simple queries', () => {
      const analysis = estimator.analyzeQuery('hello');
      const stats = createMockStats(50);
      const recommended = estimator.recommendAlgorithm(analysis, stats);

      expect(recommended).toBe('basic');
    });

    it('should prefer index-based search for large graphs', () => {
      const analysis = estimator.analyzeQuery('name:Alice');
      const stats = createMockStats(50000);
      const recommended = estimator.recommendAlgorithm(analysis, stats);

      expect(recommended).toBe('boolean');
    });
  });
});
